const input = $input.first().json || {};

function normalizePhone(raw) {
  let p = String(raw || '').trim().replace(/[^\d+]/g, '');
  if (p.startsWith('00')) p = '+' + p.slice(2);
  if (!p.startsWith('+')) {
    if (p.startsWith('380')) p = '+' + p;
    else if (p.startsWith('0')) p = '+38' + p;
    else p = '+' + p;
  }
  return p;
}

const client_phone = normalizePhone(input.phone || input.client_phone || input.Phone);
const client_name = input.client_name || input.name || input.Last_Name || 'Unknown Lead';
const company = input.company || input.Company || 'GrowthLab Lead';

return [{
  json: {
    client_name,
    client_phone,
    phone: client_phone,
    company,
    business_type: input.business_type || input.industry || '',
    source: input.source || 'CRM/Form Webhook',
    session_id: input.session_id || `gl_${Date.now()}_${Math.random().toString(16).slice(2)}`
  }
}];

const resp = $input.first().json || {};
const lead = $('Normalize Lead Data').item.json;

const happ_call_id = String(
  resp.call_id ||
  resp.id ||
  resp.conversation_id ||
  resp.chat_id ||
  resp.call?.id ||
  resp.data?.id ||
  ''
);

return [{
  json: {
    ok: true,
    event: 'happ_call_started',
    happ_call_id,
    ...lead,
    happ_response: resp
  }
}];

const err = $input.first().json || {};
const lead = $('Normalize Lead Data').item.json;

return [{
  json: {
    ok: false,
    event: 'happ_call_start_error',
    error_message: err.error?.message || err.message || JSON.stringify(err).slice(0, 500),
    ...lead,
    raw_error: err
  }
}];
